package pro.shushi.pamirs.resource.api.enmu;import pro.shushi.pamirs.meta.annotation.Errors;import pro.shushi.pamirs.meta.common.enmu.ExpBaseEnum;import pro.shushi.pamirs.meta.common.enmu.IEnum;@Errors(displayName = "资源模块错误枚举")public enum ResourceEnumerate implements ExpBaseEnum, IEnum<Integer> {    CHINESE_FORMAT_DATE_EMPTY(ERROR_TYPE.SYSTEM_ERROR, 10035000, "中文格式的日期为空或为null"),    CHINESE_YEAR_MONTH_FORMAT_DATE_EMPTY(ERROR_TYPE.SYSTEM_ERROR, 10035001, "中文年-月格式的日期为空或为null"),    HYPHEN_FORMAT_DATE_EMPTY(ERROR_TYPE.SYSTEM_ERROR, 10035002, "短横线格式的日期为空或为null"),    HYPHEN_YEAR_MONTH_FORMAT_EMPTY(ERROR_TYPE.SYSTEM_ERROR, 10035003, "短横线年-月格式的日期为空或为null"),    SLASH_FORMAT_DATE_EMPTY(ERROR_TYPE.SYSTEM_ERROR, 10035004, "斜杠格式的日期为空或为null"),    AP_COLON_NORMAL_IS_EMPTY(ERROR_TYPE.SYSTEM_ERROR, 10035005, "带AM/PM的标准时间格式为空或为null"),    AP_COLON_SHORT_IS_EMPTY(ERROR_TYPE.SYSTEM_ERROR, 10035006, "带AM/PM的简短时间格式为空或为null"),    COLON_NORMAL_IS_EMPTY(ERROR_TYPE.SYSTEM_ERROR, 10035007, "24小时制标准时间格式为空或为null"),    COLON_SHORT_IS_EMPTY(ERROR_TYPE.SYSTEM_ERROR, 10035008, "24小时制简短时间格式为空或为null"),    KEEP_LEAST_ONE_LANGUAGE(ERROR_TYPE.SYSTEM_ERROR, 10035009, "至少保留一条语言"),    SLASH_YEAR_MONTH_FORMAT_EMPTY(ERROR_TYPE.SYSTEM_ERROR, 10035010, "斜杠年-月格式的日期为空或为null");    private final ERROR_TYPE type;    private final int code;    private final String msg;    ResourceEnumerate(ERROR_TYPE type, int code, String msg) {        this.type = type;        this.code = code;        this.msg = msg;    }    @Override    public ERROR_TYPE type() {        return type;    }    @Override    public int code() {        return code;    }    @Override    public String msg() {        return msg;    }}